    for (int k = 0; k < total_sorted; k++) {
        item_weights[sorted_all[k]] = std::max(1LL, (long long)(estimated_weights_d[k] * scale));
    }

    // Exhaust remaining queries
    while (queries_made < Q_total) {
        int a = 0, b = 1;
        b = (queries_made % (N_items - 1)) + 1;
        if (b == 0) b = 1;
        perform_query({a}, {b});
    }

    // --- Partition Phase: Greedy + Simulated Annealing ---
    std::vector<int> assignment(N_items, 0);
    std::vector<long long> group_sums(D_groups, 0);
    long long total_sum = 0;

    // Sort items by weight descending for greedy
    std::vector<std::pair<long long, int>> sorted_for_greedy(N_items);
    for (int i = 0; i < N_items; i++) {
        sorted_for_greedy[i] = {-item_weights[i], i};
        total_sum += item_weights[i];
    }
    std::sort(sorted_for_greedy.begin(), sorted_for_greedy.end());

    // Greedy: assign each item to the lightest group
    std::vector<std::vector<int>> group_items(D_groups);
    for (int i = 0; i < N_items; i++) {
        int item = sorted_for_greedy[i].second;
        int best_grp = 0;
        for (int g = 1; g < D_groups; g++) {
            if (group_sums[g] < group_sums[best_grp]) best_grp = g;
        }
        assignment[item] = best_grp;
        group_sums[best_grp] += item_weights[item];
        group_items[best_grp].push_back(item);
    }

    // Compute initial variance (sum of squares)
    double sum_sq = 0;
    for (int g = 0; g < D_groups; g++) {
        sum_sq += (double)group_sums[g] * group_sums[g];
    }
    double mean = (double)total_sum / D_groups;
    double current_var = sum_sq / D_groups - mean * mean;

    // SA
    double T = std::max(1.0, current_var * 0.25);
    if (current_var < 1e-9) T = std::max(1.0, (double)total_sum / N_items * 0.1);

    std::uniform_real_distribution<double> unif(0.0, 1.0);
    std::uniform_int_distribution<int> item_dist(0, N_items - 1);
    std::uniform_int_distribution<int> group_dist(0, D_groups - 1);

    int no_improve = 0;
    const int CHECK_INTERVAL = 256;
    int iter = 0;

    while (D_groups > 1) {
        iter++;
        if (iter % CHECK_INTERVAL == 0) {
            auto now = std::chrono::steady_clock::now();
            if (std::chrono::duration_cast<std::chrono::milliseconds>(now - program_start_time) >= time_limit_ms)
                break;
            T *= 0.9999;
            if (no_improve > N_items * 15 && T < current_var * 0.05 && current_var > 1.0) {
                T = std::max(1.0, current_var * 0.125);
                no_improve = 0;
            }
        }
        if (T < 1e-12 && current_var < 1.0) break;
        if (T < 1e-12) T = 1e-9;

        bool do_swap = (rng_engine() % 3 == 0);

        if (!do_swap) {
            // Relocate
            int item = item_dist(rng_engine);
            int old_g = assignment[item];
            int new_g = group_dist(rng_engine);
            if (new_g == old_g) continue;

            long long w = item_weights[item];
            long long old_s = group_sums[old_g];
            long long new_s = group_sums[new_g];
            long long new_old_s = old_s - w;
            long long new_new_s = new_s + w;

            double new_sum_sq = sum_sq;
            new_sum_sq -= (double)old_s * old_s + (double)new_s * new_s;
            new_sum_sq += (double)new_old_s * new_old_s + (double)new_new_s * new_new_s;
            double new_var = new_sum_sq / D_groups - mean * mean;
            double delta = new_var - current_var;

            if (delta < 0 || (T > 1e-12 && unif(rng_engine) < std::exp(-delta / T))) {
                current_var = new_var;
                sum_sq = new_sum_sq;
                group_sums[old_g] = new_old_s;
                group_sums[new_g] = new_new_s;
                assignment[item] = new_g;

                // Update group_items
                auto& old_vec = group_items[old_g];
                old_vec.erase(std::find(old_vec.begin(), old_vec.end(), item));
                group_items[new_g].push_back(item);

                no_improve = (delta < -1e-9) ? 0 : no_improve + 1;
            } else {
                no_improve++;
            }
        } else {
            // Swap
            int g1 = group_dist(rng_engine);
            int g2 = group_dist(rng_engine);
            if (g1 == g2 || group_items[g1].empty() || group_items[g2].empty()) continue;

            int item1 = group_items[g1][rng_engine() % group_items[g1].size()];
            int item2 = group_items[g2][rng_engine() % group_items[g2].size()];

            long long w1 = item_weights[item1];
            long long w2 = item_weights[item2];

            long long old_s1 = group_sums[g1];
            long long old_s2 = group_sums[g2];
            long long new_s1 = old_s1 - w1 + w2;
            long long new_s2 = old_s2 - w2 + w1;

            double new_sum_sq = sum_sq;
            new_sum_sq -= (double)old_s1 * old_s1 + (double)old_s2 * old_s2;
            new_sum_sq += (double)new_s1 * new_s1 + (double)new_s2 * new_s2;
            double new_var = new_sum_sq / D_groups - mean * mean;
            double delta = new_var - current_var;

            if (delta < 0 || (T > 1e-12 && unif(rng_engine) < std::exp(-delta / T))) {
                current_var = new_var;
                sum_sq = new_sum_sq;
                group_sums[g1] = new_s1;
                group_sums[g2] = new_s2;
                assignment[item1] = g2;
                assignment[item2] = g1;

                auto& v1 = group_items[g1];
                auto& v2 = group_items[g2];
                v1.erase(std::find(v1.begin(), v1.end(), item1));
                v2.erase(std::find(v2.begin(), v2.end(), item2));
                v1.push_back(item2);
                v2.push_back(item1);

                no_improve = (delta < -1e-9) ? 0 : no_improve + 1;
            } else {
                no_improve++;
            }
        }
    }

    // Output
    for (int i = 0; i < N_items; i++) {
        std::cout << assignment[i] << (i == N_items - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}
