                std::vector<int> right_set;
                for (int i = 0; i < mid_cal; i++) right_set.push_back(sorted_all[i]);

                char res = perform_query({sorted_all[mid_item_rank]}, right_set);
                if (res == '>') {
                    last_greater_mid = mid_cal;
                    lo_cal = mid_cal + 1;
                } else if (res == '<') {
                    hi_cal = mid_cal - 1;
                } else {
                    last_greater_mid = mid_cal;
                    break;
                }
            }
            k_mid = last_greater_mid;
        }
    }

