char compare_items(int a, int b) {
    if (a == b) return '=';
    auto key = std::make_pair(std::min(a,b), std::max(a,b));
    auto it = cache_1v1.find(key);
    if (it != cache_1v1.end()) {
        char c = it->second;
        return (a == key.first) ? c : (c == '<' ? '>' : (c == '>' ? '<' : '='));
    }
    if (queries_made >= Q_total) return '=';
    char res = perform_query({a}, {b});
    char stored = (a < b) ? res : (res == '<' ? '>' : (res == '>' ? '<' : '='));
    cache_1v1[key] = stored;
    return res;
}

void merge_sort(std::vector<int>& arr, int left, int right) {
    if (left >= right) return;
    int mid = left + (right - left) / 2;
    merge_sort(arr, left, mid);
    merge_sort(arr, mid + 1, right);
    std::vector<int> tmp;
    int i = left, j = mid + 1;
    while (i <= mid && j <= right) {
        char c = compare_items(arr[i], arr[j]);
        if (c == '<' || c == '=') tmp.push_back(arr[i++]);
        else tmp.push_back(arr[j++]);
    }
    while (i <= mid) tmp.push_back(arr[i++]);
    while (j <= right) tmp.push_back(arr[j++]);
    for (int k = 0; k < (int)tmp.size(); k++) arr[left + k] = tmp[k];
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    program_start_time = std::chrono::steady_clock::now();
    rng_engine.seed(std::chrono::duration_cast<std::chrono::nanoseconds>(
        std::chrono::steady_clock::now().time_since_epoch()).count());

    std::cin >> N_items >> D_groups >> Q_total;

    // Sort all items using merge sort
    std::vector<int> sorted_items(N_items);
    std::iota(sorted_items.begin(), sorted_items.end(), 0);
    std::shuffle(sorted_items.begin(), sorted_items.end(), rng_engine);
    merge_sort(sorted_items, 0, N_items - 1);

    // After sorting, use remaining queries for calibration:
    // Compare single items vs groups of consecutive items to determine
    // the weight curve steepness.

    // For exponential distribution with lambda, expected weight at rank k (0-indexed) is:
    // E[w_{(k)}] = (1/lambda) * sum_{j=1}^{N} 1/(N-j+1) for j=1..k+1
    // = (1/lambda) * (H(N) - H(N-k-1))
    // where H(n) is the n-th harmonic number

    // The shape depends on lambda. We can find it using calibration queries.
    // Compare item at rank R vs sum of items at ranks 0..m-1.
    // If item[R] > sum(item[0]..item[m-1]), this gives constraint on lambda.

    // But actually, for the purpose of SA partitioning, what matters is relative weights.
    // The shape is ALWAYS the same for exponential order statistics regardless of lambda.
    // So we can just use the expected order statistics directly!

    // Expected value of k-th order statistic (0-indexed) from Exp(1) with sample size N:
    // E[X_{(k+1:N)}] = sum_{j=0}^{k} 1/(N-j)

    std::vector<double> expected_os(N_items);
    for (int k = 0; k < N_items; k++) {
        double val = 0.0;
        for (int j = 0; j <= k; j++) {
            val += 1.0 / (N_items - j);
        }
        expected_os[k] = val;
    }

    // However, the actual problem says weights are max(1, round(Exp(lambda=10^-5)))
    // with truncation at 10^5 * N / D. The "max(1, round())" and truncation
    // can distort the shape, especially for small items (many will be 1).
    // But for relative proportions, this is a reasonable model.

    // CALIBRATION: Use queries to adjust the model.
    // Binary search: find M such that sorted_items[N-1] > sum(sorted_items[0..M-1])
    // This tells us how "skewed" the distribution really is.

    // With remaining budget, try to calibrate
    int remaining = Q_total - queries_made;

    // We'll do binary search calibration if we have budget
    int k_top = -1; // largest M such that item[N-1] > sum(item[0..M-1])

    if (remaining >= 5 && N_items >= 4) {
        int lo = 1, hi = N_items - 2;
        int last_greater = 0;

        while (lo <= hi && queries_made < Q_total) {
            int mid = lo + (hi - lo) / 2;
            std::vector<int> right_set;
            for (int i = 0; i < mid; i++) right_set.push_back(sorted_items[i]);

            char res = perform_query({sorted_items[N_items - 1]}, right_set);
            if (res == '>') {
                last_greater = mid;
                lo = mid + 1;
            } else if (res == '<') {
                hi = mid - 1;
            } else {
                last_greater = mid;
                break;
            }
        }
        k_top = last_greater;
    }

    // Also try to find how many smallest items = the median item
    int k_med = -1;
    if (remaining >= 10 && N_items >= 6 && queries_made < Q_total) {
        int med_rank = N_items / 2;
        int lo = 1, hi = med_rank - 1;
        int last_greater = 0;

        while (lo <= hi && queries_made < Q_total) {
            int mid = lo + (hi - lo) / 2;
            std::vector<int> right_set;
            for (int i = 0; i < mid; i++) right_set.push_back(sorted_items[i]);

            char res = perform_query({sorted_items[med_rank]}, right_set);
            if (res == '>') {
                last_greater = mid;
                lo = mid + 1;
            } else if (res == '<') {
                hi = mid - 1;
            } else {
                last_greater = mid;
                break;
            }
        }
        k_med = last_greater;
    }

