    // if M = k_top. But in practice the shape may differ.

    // Find alpha such that expected_os[N-1]^alpha ≈ sum(expected_os[0..k_top-1]^alpha)
    // if k_top > 0

    double alpha = 1.0;

    if (k_top > 0 && k_top < N_items - 1) {
        double alpha_lo = 0.1, alpha_hi = 10.0;
        for (int iter = 0; iter < 60; iter++) {
            double alpha_mid = (alpha_lo + alpha_hi) / 2.0;
            double largest_w = std::pow(expected_os[N_items - 1], alpha_mid);
            double sum_w = 0;
            for (int i = 0; i < k_top; i++) {
                sum_w += std::pow(expected_os[i], alpha_mid);
            }
            if (largest_w > sum_w) {
                alpha_hi = alpha_mid;
            } else {
                alpha_lo = alpha_mid;
            }
        }
        alpha = (alpha_lo + alpha_hi) / 2.0;
    }

    // Second calibration with k_med
    double alpha2 = alpha;
    if (k_med > 0 && k_med < N_items / 2) {
        int med_rank = N_items / 2;
        double a_lo = 0.1, a_hi = 10.0;
        for (int iter = 0; iter < 60; iter++) {
            double a_mid = (a_lo + a_hi) / 2.0;
            double med_w = std::pow(expected_os[med_rank], a_mid);
            double sum_w = 0;
            for (int i = 0; i < k_med; i++) {
                sum_w += std::pow(expected_os[i], a_mid);
            }
            if (med_w > sum_w) {
                a_hi = a_mid;
            } else {
                a_lo = a_mid;
            }
        }
        alpha2 = (a_lo + a_hi) / 2.0;
    }

    // Average the two calibrations
    if (k_med > 0 && k_top > 0) {
        alpha = (alpha + alpha2) / 2.0;
    }

    // Compute final weights
    std::vector<long long> item_weights(N_items);
    double scale = 100000.0;
    for (int k = 0; k < N_items; k++) {
        double w = std::pow(expected_os[k], alpha) * scale;
        item_weights[sorted_items[k]] = std::max(1LL, (long long)w);
    }

    // Exhaust remaining queries
    while (queries_made < Q_total) {
        perform_query({sorted_items[0]}, {sorted_items[std::min(1, N_items - 1)]});
    }

