            // Find the heaviest item in heavy_g and lightest item in light_g
            // and swap if it reduces imbalance
            int heaviest_in_heavy = -1;
            int lightest_in_light = -1;
            int max_rank_h = -1, min_rank_l = N_items;

            for (int item : group_items[heavy_g]) {
