    { int tmp = N_items; while (tmp > 1) { log_n++; tmp /= 2; } }

    int num_probes = std::min(remaining / std::max(1, log_n), N_items - 2);

    // probe_indices: indices into sorted_items that we'll probe (evenly spaced from top)
    std::vector<int> probe_ranks;
    if (num_probes > 0) {
        int step = std::max(1, (N_items - 2) / num_probes);
        for (int r = N_items - 1; r >= 2 && (int)probe_ranks.size() < num_probes; r -= step) {
            probe_ranks.push_back(r);
        }
    }

    // For each probed rank, find the breakpoint
    // breakpoint[r] = largest m such that sorted[r] > sum(sorted[0..m-1])
    std::vector<int> breakpoint(N_items, -1); // -1 means unknown

    for (int r : probe_ranks) {
        if (queries_made >= Q_total) break;

        int lo = 1, hi = r - 1; // sorted[r] vs sum of sorted[0..mid-1]
        int last_greater = 0;

        while (lo <= hi && queries_made < Q_total) {
            int mid = lo + (hi - lo) / 2;
            std::vector<int> right_set;
            for (int i = 0; i < mid; i++) right_set.push_back(sorted_items[i]);

            char res = perform_query({sorted_items[r]}, right_set);
            if (res == '>') {
                last_greater = mid;
                lo = mid + 1;
            } else if (res == '<') {
                hi = mid - 1;
            } else {
                last_greater = mid;
                break;
            }
        }
        breakpoint[r] = last_greater;
    }

    // Now build weight estimates using the breakpoints.
    // If breakpoint[r] = m, then w[r] ≈ sum(w[0..m-1])
    // We'll iteratively build up weights from smallest to largest.

    // Start with w[0] = 1 (base weight for lightest item)
    std::vector<double> weights(N_items, 0.0);
    weights[0] = 1.0;

    // First pass: for items without a breakpoint, interpolate using those that have one.
    // For items with a breakpoint, w[r] = prefix_sum[breakpoint[r]]
    // We need to build prefix sums iteratively.

    // Actually let's set up a system where we go from bottom to top:
    // Initially assume uniform spacing. Then adjust based on breakpoints.

    // Better approach: Use breakpoints to determine a consistent weight assignment.
    // w[r] should satisfy: w[r] ≈ sum(w[0..breakpoint[r]-1]) for known breakpoints.
    // And w[r] >= w[r-1] (sorted order).

    // Start simple: assign w[0] = 1. For each r from 1 to N-1:
    // If breakpoint[r] is known, set w[r] = prefix_sum up to breakpoint[r]
    // Otherwise, interpolate geometrically between known breakpoints.

    // Compute prefix sums iteratively
    // We'll process items in order. For unknown items between known breakpoints,
    // we'll use geometric interpolation.

    // First, identify known breakpoints and sort them
    std::vector<std::pair<int, int>> known_bp; // (rank, breakpoint)
    for (int r = 0; r < N_items; r++) {
        if (breakpoint[r] >= 0) {
            known_bp.push_back({r, breakpoint[r]});
        }
    }
    std::sort(known_bp.begin(), known_bp.end());

    // If no breakpoints known, fall back to expected exponential order statistics
    if (known_bp.empty()) {
        for (int k = 0; k < N_items; k++) {
            double val = 0.0;
            for (int j = 0; j <= k; j++) val += 1.0 / (N_items - j);
            weights[k] = val;
        }
    } else {
        // Iterative weight building
        // w[0] = 1
        // For each known breakpoint at rank r with value m:
        // w[r] = sum(w[0..m-1])
        // For items between known breakpoints, interpolate.

        // Build weights bottom-up
        weights[0] = 1.0;
        std::vector<double> prefix(N_items + 1, 0.0);
        prefix[1] = weights[0];

        int next_known = 0; // index into known_bp

        for (int r = 1; r < N_items; r++) {
            if (next_known < (int)known_bp.size() && known_bp[next_known].first == r) {
                int m = known_bp[next_known].second;
                if (m > 0 && prefix[m] > 0) {
                    weights[r] = prefix[m];
                } else {
                    // Fallback: slightly more than previous
                    weights[r] = weights[r-1] * 1.1;
                }
                // Ensure monotonicity
                weights[r] = std::max(weights[r], weights[r-1]);
                next_known++;
            } else {
                // Interpolate: find next known breakpoint above r
                int next_r = N_items; // sentinel
                double next_w = -1;
                if (next_known < (int)known_bp.size()) {
                    next_r = known_bp[next_known].first;
                    int next_m = known_bp[next_known].second;
                    // Estimate what w[next_r] would be given current prefix
                    // But we don't know prefix yet... use geometric growth as default
                }

                // Simple default: geometric growth from previous item
                // Use ratio estimated from nearest known breakpoints
                double ratio = 1.0;
                if (r >= 2 && weights[r-1] > 0 && weights[r-2] > 0) {
                    ratio = weights[r-1] / weights[r-2];
                    ratio = std::max(1.0, std::min(ratio, 3.0)); // clamp
                }
                weights[r] = weights[r-1] * ratio;
                weights[r] = std::max(weights[r], weights[r-1]);
            }
            prefix[r+1] = prefix[r] + weights[r];
        }

        // Second pass: readjust based on known breakpoints
        // Recompute prefix and check consistency
        prefix[0] = 0;
        for (int r = 0; r < N_items; r++) prefix[r+1] = prefix[r] + weights[r];

        for (auto& [r, m] : known_bp) {
            if (m > 0 && m < r) {
                double target = prefix[m]; // w[r] should equal sum(w[0..m-1])
                if (target > 0 && weights[r] > 0) {
                    double ratio_fix = target / weights[r];
                    // Don't adjust too aggressively
                    if (ratio_fix > 0.5 && ratio_fix < 2.0) {
                        weights[r] *= ratio_fix;
                    }
                }
            }
        }

        // Ensure monotonicity after adjustment
        for (int r = 1; r < N_items; r++) {
            weights[r] = std::max(weights[r], weights[r-1]);
        }
    }

    // Convert to integer weights
    double scale = 100000.0 / std::max(1.0, weights[N_items / 2]);
    std::vector<long long> item_weights(N_items);
    for (int k = 0; k < N_items; k++) {
        item_weights[sorted_items[k]] = std::max(1LL, (long long)(weights[k] * scale));
    }

    // Exhaust remaining queries
    while (queries_made < Q_total) {
        perform_query({sorted_items[0]}, {sorted_items[std::min(1, N_items - 1)]});
    }

    // --- Partition Phase: Greedy + SA ---
    std::vector<int> assignment(N_items, 0);
    std::vector<long long> group_sums(D_groups, 0);
    long long total_sum = 0;

    std::vector<std::pair<long long, int>> sorted_for_greedy(N_items);
    for (int i = 0; i < N_items; i++) {
        sorted_for_greedy[i] = {-item_weights[i], i};
        total_sum += item_weights[i];
    }
    std::sort(sorted_for_greedy.begin(), sorted_for_greedy.end());

    std::vector<std::vector<int>> group_items_vec(D_groups);
    for (int i = 0; i < N_items; i++) {
        int item = sorted_for_greedy[i].second;
        int best_grp = 0;
        for (int g = 1; g < D_groups; g++) {
            if (group_sums[g] < group_sums[best_grp]) best_grp = g;
        }
        assignment[item] = best_grp;
        group_sums[best_grp] += item_weights[item];
        group_items_vec[best_grp].push_back(item);
    }

    double sum_sq = 0;
    for (int g = 0; g < D_groups; g++) {
        sum_sq += (double)group_sums[g] * group_sums[g];
    }
    double mean_val = (double)total_sum / D_groups;
    double current_var = sum_sq / D_groups - mean_val * mean_val;

    double T = std::max(1.0, current_var * 0.25);
    if (current_var < 1e-9) T = std::max(1.0, (double)total_sum / N_items * 0.1);

    std::uniform_real_distribution<double> unif(0.0, 1.0);
    std::uniform_int_distribution<int> item_dist(0, N_items - 1);
    std::uniform_int_distribution<int> group_dist(0, D_groups - 1);

    int no_improve = 0;
    const int CHECK_INTERVAL = 256;
    int iter_count = 0;

    while (D_groups > 1) {
        iter_count++;
        if (iter_count % CHECK_INTERVAL == 0) {
            auto now = std::chrono::steady_clock::now();
            if (std::chrono::duration_cast<std::chrono::milliseconds>(now - program_start_time) >= time_limit_ms)
                break;
            T *= 0.9999;
            if (no_improve > N_items * 15 && T < current_var * 0.05 && current_var > 1.0) {
                T = std::max(1.0, current_var * 0.125);
                no_improve = 0;
            }
        }
        if (T < 1e-12 && current_var < 1.0) break;
        if (T < 1e-12) T = 1e-9;

        bool do_swap = (rng_engine() % 3 == 0);

        if (!do_swap) {
            int item = item_dist(rng_engine);
            int old_g = assignment[item];
            int new_g = group_dist(rng_engine);
            if (new_g == old_g) continue;

            long long w = item_weights[item];
            long long old_s = group_sums[old_g];
            long long new_s = group_sums[new_g];
            long long new_old_s = old_s - w;
            long long new_new_s = new_s + w;

            double new_sum_sq = sum_sq;
            new_sum_sq -= (double)old_s * old_s + (double)new_s * new_s;
            new_sum_sq += (double)new_old_s * new_old_s + (double)new_new_s * new_new_s;
            double new_var = new_sum_sq / D_groups - mean_val * mean_val;
            double delta = new_var - current_var;

            if (delta < 0 || (T > 1e-12 && unif(rng_engine) < std::exp(-delta / T))) {
                current_var = new_var;
                sum_sq = new_sum_sq;
                group_sums[old_g] = new_old_s;
                group_sums[new_g] = new_new_s;
                assignment[item] = new_g;
                no_improve = (delta < -1e-9) ? 0 : no_improve + 1;
            } else {
                no_improve++;
            }
        } else {
            int g1 = group_dist(rng_engine);
            int g2 = group_dist(rng_engine);
            if (g1 == g2) continue;
            if (group_items_vec[g1].empty() || group_items_vec[g2].empty()) continue;

            int idx1 = rng_engine() % group_items_vec[g1].size();
            int idx2 = rng_engine() % group_items_vec[g2].size();
            int item1 = group_items_vec[g1][idx1];
            int item2 = group_items_vec[g2][idx2];

            long long w1 = item_weights[item1];
            long long w2 = item_weights[item2];

            long long old_s1 = group_sums[g1];
            long long old_s2 = group_sums[g2];
            long long new_s1 = old_s1 - w1 + w2;
            long long new_s2 = old_s2 - w2 + w1;

            double new_sum_sq = sum_sq;
            new_sum_sq -= (double)old_s1 * old_s1 + (double)old_s2 * old_s2;
            new_sum_sq += (double)new_s1 * new_s1 + (double)new_s2 * new_s2;
            double new_var = new_sum_sq / D_groups - mean_val * mean_val;
            double delta = new_var - current_var;

            if (delta < 0 || (T > 1e-12 && unif(rng_engine) < std::exp(-delta / T))) {
                current_var = new_var;
                sum_sq = new_sum_sq;
                group_sums[g1] = new_s1;
                group_sums[g2] = new_s2;
                assignment[item1] = g2;
                assignment[item2] = g1;
                group_items_vec[g1][idx1] = item2;
                group_items_vec[g2][idx2] = item1;
                no_improve = (delta < -1e-9) ? 0 : no_improve + 1;
            } else {
                no_improve++;
            }
        }
    }

    for (int i = 0; i < N_items; i++) {
        std::cout << assignment[i] << (i == N_items - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}
